func TestGetEnrollmentHandler_Response(t *testing.T) {
	t.Run("構造行0件は空sectionsとnextTopic=nullを返す", func(t *testing.T) {
		h := NewGetEnrollmentHandler(&mockGetEnrollmentQuery{
			authority: publishedAuthority(t),
