	t.Run("進捗0件のとき各topic.statusはnull、nextTopicは先頭トピック", func(t *testing.T) {
		rows := []db.GetCourseStructureWithProgressRow{
			fixedRow(t, validSection0ID, "セクション0", validTopic00ID, "T0-0", pgtype.Text{}, pgtype.Timestamptz{}),
			fixedRow(t, validSection0ID, "セクション0", validTopic01ID, "T0-1", pgtype.Text{}, pgtype.Timestamptz{}),
		}
		h := NewGetEnrollmentHandler(&mockGetEnrollmentQuery{
			authority: publishedAuthority(t),
			rows:      rows,
		})
		w := httptest.NewRecorder()
		h.GetEnrollmentHandler(w, newGetEnrollmentRequest(t, validUserID, validCourseID))

		assert.Equal(t, http.StatusOK, w.Result().StatusCode)
		// 生 JSON で null を厳密確認
		raw, _ := json.Marshal(map[string]any{"_": json.RawMessage(w.Body.Bytes())})
		assert.Contains(t, string(raw), `"status":null`)

		var body GetEnrollmentResponse
		if err := json.NewDecoder(w.Result().Body).Decode(&body); err != nil {
			t.Fatalf("decode failed: %v", err)
		}
		assert.Len(t, body.Sections, 1)
		assert.Len(t, body.Sections[0].Topics, 2)
		assert.Nil(t, body.Sections[0].Topics[0].Status)
		assert.Equal(t, validTopic00ID, body.NextTopic.TopicId)
	})

	t.Run("最新進捗がIN_PROGRESSならそのトピックがnextTopic", func(t *testing.T) {
		base := time.Date(2026, 4, 1, 0, 0, 0, 0, time.UTC)
		rows := []db.GetCourseStructureWithProgressRow{
			fixedRow(t, validSection0ID, "S0", validTopic00ID, "T0-0", progressText("COMPLETED"), progressTime(base)),
			fixedRow(t, validSection0ID, "S0", validTopic01ID, "T0-1", progressText("IN_PROGRESS"), progressTime(base.Add(time.Hour))),
			fixedRow(t, validSection1ID, "S1", validTopic10ID, "T1-0", pgtype.Text{}, pgtype.Timestamptz{}),
		}
		h := NewGetEnrollmentHandler(&mockGetEnrollmentQuery{
			authority: publishedAuthority(t),
			rows:      rows,
		})
		w := httptest.NewRecorder()
		h.GetEnrollmentHandler(w, newGetEnrollmentRequest(t, validUserID, validCourseID))

		var body GetEnrollmentResponse
		if err := json.NewDecoder(w.Result().Body).Decode(&body); err != nil {
			t.Fatalf("decode failed: %v", err)
		}
		assert.NotNil(t, body.NextTopic)
		assert.Equal(t, validTopic01ID, body.NextTopic.TopicId)
		assert.Equal(t, validSection0ID, body.NextTopic.SectionId)
	})

	t.Run("最新進捗がCOMPLETEDかつ次トピックがあればそれをnextTopic", func(t *testing.T) {
		base := time.Date(2026, 4, 1, 0, 0, 0, 0, time.UTC)
		rows := []db.GetCourseStructureWithProgressRow{
			fixedRow(t, validSection0ID, "S0", validTopic00ID, "T0-0", progressText("COMPLETED"), progressTime(base)),
			fixedRow(t, validSection0ID, "S0", validTopic01ID, "T0-1", pgtype.Text{}, pgtype.Timestamptz{}),
			fixedRow(t, validSection1ID, "S1", validTopic10ID, "T1-0", pgtype.Text{}, pgtype.Timestamptz{}),
		}
		h := NewGetEnrollmentHandler(&mockGetEnrollmentQuery{
			authority: publishedAuthority(t),
			rows:      rows,
		})
		w := httptest.NewRecorder()
		h.GetEnrollmentHandler(w, newGetEnrollmentRequest(t, validUserID, validCourseID))

		var body GetEnrollmentResponse
		if err := json.NewDecoder(w.Result().Body).Decode(&body); err != nil {
			t.Fatalf("decode failed: %v", err)
		}
		assert.NotNil(t, body.NextTopic)
		assert.Equal(t, validTopic01ID, body.NextTopic.TopicId)
	})

	t.Run("全COMPLETEDならnextTopicはnull", func(t *testing.T) {
		base := time.Date(2026, 4, 1, 0, 0, 0, 0, time.UTC)
		rows := []db.GetCourseStructureWithProgressRow{
			fixedRow(t, validSection0ID, "S0", validTopic00ID, "T0-0", progressText("COMPLETED"), progressTime(base)),
			fixedRow(t, validSection0ID, "S0", validTopic01ID, "T0-1", progressText("COMPLETED"), progressTime(base.Add(time.Hour))),
			fixedRow(t, validSection1ID, "S1", validTopic10ID, "T1-0", progressText("COMPLETED"), progressTime(base.Add(2*time.Hour))),
		}
		h := NewGetEnrollmentHandler(&mockGetEnrollmentQuery{
			authority: publishedAuthority(t),
			rows:      rows,
		})
		w := httptest.NewRecorder()
		h.GetEnrollmentHandler(w, newGetEnrollmentRequest(t, validUserID, validCourseID))

		var body GetEnrollmentResponse
		if err := json.NewDecoder(w.Result().Body).Decode(&body); err != nil {
			t.Fatalf("decode failed: %v", err)
		}
		assert.Nil(t, body.NextTopic)
	})

	t.Run("courseIdとセクション/トピック構造を正しく返す", func(t *testing.T) {
		base := time.Date(2026, 4, 1, 0, 0, 0, 0, time.UTC)
		rows := []db.GetCourseStructureWithProgressRow{
			fixedRow(t, validSection0ID, "S0", validTopic00ID, "T0-0", progressText("IN_PROGRESS"), progressTime(base)),
			fixedRow(t, validSection0ID, "S0", validTopic01ID, "T0-1", pgtype.Text{}, pgtype.Timestamptz{}),
			fixedRow(t, validSection1ID, "S1", validTopic10ID, "T1-0", pgtype.Text{}, pgtype.Timestamptz{}),
		}
		h := NewGetEnrollmentHandler(&mockGetEnrollmentQuery{
			authority: publishedAuthority(t),
			rows:      rows,
		})
		w := httptest.NewRecorder()
		h.GetEnrollmentHandler(w, newGetEnrollmentRequest(t, validUserID, validCourseID))

		var body GetEnrollmentResponse
		if err := json.NewDecoder(w.Result().Body).Decode(&body); err != nil {
			t.Fatalf("decode failed: %v", err)
		}
		assert.Equal(t, validCourseID, body.CourseId)
		assert.Len(t, body.Sections, 2)
		assert.Equal(t, validSection0ID, body.Sections[0].SectionId)
		assert.Equal(t, "S0", body.Sections[0].Title)
		assert.Len(t, body.Sections[0].Topics, 2)
		assert.Equal(t, "IN_PROGRESS", *body.Sections[0].Topics[0].Status)
		assert.Nil(t, body.Sections[0].Topics[1].Status)
		assert.Equal(t, validSection1ID, body.Sections[1].SectionId)
	})
}

func TestDecideNextTopic(t *testing.T) {
	base := time.Date(2026, 4, 1, 0, 0, 0, 0, time.UTC)

	t.Run("rowsが空ならnil", func(t *testing.T) {
		got := decideNextTopic(nil)
		assert.Nil(t, got)
	})

	t.Run("同timestampなら後ろの行を採用 (タイブレーク)", func(t *testing.T) {
		rows := []db.GetCourseStructureWithProgressRow{
			fixedRow(t, validSection0ID, "S0", validTopic00ID, "T0", progressText("IN_PROGRESS"), progressTime(base)),
			fixedRow(t, validSection0ID, "S0", validTopic01ID, "T1", progressText("COMPLETED"), progressTime(base)),
			fixedRow(t, validSection1ID, "S1", validTopic10ID, "T2", pgtype.Text{}, pgtype.Timestamptz{}),
		}
		got := decideNextTopic(rows)
		// 同 timestamp → 後ろ (T1 = COMPLETED) → 次の T2
		assert.NotNil(t, got)
		assert.Equal(t, validTopic10ID, got.TopicId)
	})

	t.Run("最終トピック完了かつ過去に未完了の穴があればそれを返す", func(t *testing.T) {
		rows := []db.GetCourseStructureWithProgressRow{
			fixedRow(t, validSection0ID, "S0", validTopic00ID, "T0", progressText("IN_PROGRESS"), progressTime(base)),
			fixedRow(t, validSection0ID, "S0", validTopic01ID, "T1", pgtype.Text{}, pgtype.Timestamptz{}),
			fixedRow(t, validSection1ID, "S1", validTopic10ID, "T2", progressText("COMPLETED"), progressTime(base.Add(2*time.Hour))),
		}
		got := decideNextTopic(rows)
		// 最新は T2 COMPLETED で末尾 → 過去の未完了 (T0 IN_PROGRESS) を返す
		assert.NotNil(t, got)
		assert.Equal(t, validTopic00ID, got.TopicId)
	})
}

func fixedRow(t *testing.T, sectionID, sectionTitle, topicID, topicTitle string, status pgtype.Text, updatedAt pgtype.Timestamptz) db.GetCourseStructureWithProgressRow {
	t.Helper()
	return db.GetCourseStructureWithProgressRow{
		SectionID:         mustUUID(t, sectionID),
		SectionTitle:      sectionTitle,
		TopicID:           mustUUID(t, topicID),
		TopicTitle:        topicTitle,
		ProgressStatus:    status,
		ProgressUpdatedAt: updatedAt,
	}
}

