		var body GetEnrollmentResponse
		if err := json.NewDecoder(w.Result().Body).Decode(&body); err != nil {
			t.Fatalf("decode failed: %v", err)
		}
		assert.NotNil(t, body.NextTopic)
		assert.Equal(t, validTopic01ID, body.NextTopic.TopicId)
	})

	t.Run("全COMPLETEDならnextTopicはnull", func(t *testing.T) {
		base := time.Date(2026, 4, 1, 0, 0, 0, 0, time.UTC)
		rows := []db.GetCourseStructureWithProgressRow{
			fixedRow(t, validSection0ID, "S0", validTopic00ID, "T0-0", progressText("COMPLETED"), progressTime(base)),
			fixedRow(t, validSection0ID, "S0", validTopic01ID, "T0-1", progressText("COMPLETED"), progressTime(base.Add(time.Hour))),
			fixedRow(t, validSection1ID, "S1", validTopic10ID, "T1-0", progressText("COMPLETED"), progressTime(base.Add(2*time.Hour))),
		}
		h := NewGetEnrollmentHandler(&mockGetEnrollmentQuery{
			authority: publishedAuthority(t),
			rows:      rows,
		})
		w := httptest.NewRecorder()
		h.GetEnrollmentHandler(w, newGetEnrollmentRequest(t, validUserID, validCourseID))

		var body GetEnrollmentResponse
		if err := json.NewDecoder(w.Result().Body).Decode(&body); err != nil {
			t.Fatalf("decode failed: %v", err)
		}
		assert.Nil(t, body.NextTopic)
	})

	t.Run("courseIdとセクション/トピック構造を正しく返す", func(t *testing.T) {
		base := time.Date(2026, 4, 1, 0, 0, 0, 0, time.UTC)
		rows := []db.GetCourseStructureWithProgressRow{
			fixedRow(t, validSection0ID, "S0", validTopic00ID, "T0-0", progressText("IN_PROGRESS"), progressTime(base)),
			fixedRow(t, validSection0ID, "S0", validTopic01ID, "T0-1", pgtype.Text{}, pgtype.Timestamptz{}),
			fixedRow(t, validSection1ID, "S1", validTopic10ID, "T1-0", pgtype.Text{}, pgtype.Timestamptz{}),
