		}
		if body.NextTopic.TopicId != mediumTestTopicA1ID {
			t.Errorf("nextTopic は A1 を期待: got %s", body.NextTopic.TopicId)
		}
	})

	t.Run("最新COMPLETEDかつ次トピックがあればそれをnextTopic", func(t *testing.T) {
