package queries

import (
	"context"
	"encoding/json"
	"errors"
	"log"
	"net/http"

	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/harusame0616/ijuku/apps/api/lib/response"
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgtype"
)

const (
	progressStatusInProgress = "IN_PROGRESS"
	progressStatusCompleted  = "COMPLETED"
	coursePublishStatusPub   = "published"
)

type GetEnrollmentQuery interface {
	GetCourseAuthorityById(ctx context.Context, courseid pgtype.UUID) (db.GetCourseAuthorityByIdRow, error)
	GetCourseStructureWithProgress(ctx context.Context, arg db.GetCourseStructureWithProgressParams) ([]db.GetCourseStructureWithProgressRow, error)
}

type GetEnrollmentHandler struct {
	query GetEnrollmentQuery
}

func NewGetEnrollmentHandler(q GetEnrollmentQuery) *GetEnrollmentHandler {
	return &GetEnrollmentHandler{query: q}
}

type getEnrollmentTopicResponse struct {
	TopicId string  `json:"topicId"`
	Title   string  `json:"title"`
	Status  *string `json:"status"`
}

type getEnrollmentSectionResponse struct {
	SectionId string                       `json:"sectionId"`
	Title     string                       `json:"title"`
	Topics    []getEnrollmentTopicResponse `json:"topics"`
}

type getEnrollmentNextTopicResponse struct {
	SectionId string `json:"sectionId"`
	TopicId   string `json:"topicId"`
}

type GetEnrollmentResponse struct {
	CourseId  string                          `json:"courseId"`
	Sections  []getEnrollmentSectionResponse  `json:"sections"`
	NextTopic *getEnrollmentNextTopicResponse `json:"nextTopic"`
}

func (h *GetEnrollmentHandler) GetEnrollmentHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	var userID pgtype.UUID
	if err := userID.Scan(r.PathValue("userID")); err != nil {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "userID must be a valid UUID")
		return
	}

	var courseID pgtype.UUID
	if err := courseID.Scan(r.PathValue("courseId")); err != nil {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "courseId must be a valid UUID")
		return
	}

	authority, err := h.query.GetCourseAuthorityById(r.Context(), courseID)
	if err != nil {
		if errors.Is(err, pgx.ErrNoRows) {
			response.WriteErrorResponse(w, http.StatusNotFound, response.CourseNotFoundError, "course not found")
			return
		}
		log.Printf("GetCourseAuthorityById error: %v", err)
		response.WriteInternalServerErrorResponse(w)
		return
	}

	if authority.PublishStatus != coursePublishStatusPub && authority.AuthorID.Bytes != userID.Bytes {
		response.WriteErrorResponse(w, http.StatusForbidden, response.EnrollmentForbidden, "this course is not enrollable")
		return
	}

	rows, err := h.query.GetCourseStructureWithProgress(r.Context(), db.GetCourseStructureWithProgressParams{
		CourseId: courseID,
		UserId:   userID,
	})
	if err != nil {
		log.Printf("GetCourseStructureWithProgress error: %v", err)
		response.WriteInternalServerErrorResponse(w)
		return
	}

	_ = json.NewEncoder(w).Encode(GetEnrollmentResponse{
		CourseId:  courseID.String(),
		Sections:  buildSections(rows),
		NextTopic: decideNextTopic(rows),
	})
}

func buildSections(rows []db.GetCourseStructureWithProgressRow) []getEnrollmentSectionResponse {
	sections := []getEnrollmentSectionResponse{}
	var current *getEnrollmentSectionResponse
	for _, row := range rows {
		if current == nil || current.SectionId != row.SectionID.String() {
			sections = append(sections, getEnrollmentSectionResponse{
				SectionId: row.SectionID.String(),
				Title:     row.SectionTitle,
				Topics:    []getEnrollmentTopicResponse{},
			})
			current = &sections[len(sections)-1]
		}
		current.Topics = append(current.Topics, getEnrollmentTopicResponse{
			TopicId: row.TopicID.String(),
			Title:   row.TopicTitle,
			Status:  progressStatusOrNil(row.ProgressStatus),
		})
	}
	return sections
}

func progressStatusOrNil(t pgtype.Text) *string {
	if !t.Valid {
		return nil
	}
	v := t.String
	return &v
}

// decideNextTopic は user_topic_progresses の最新進捗 (progress_updated_at の最大行) から
// 「次に取るべき topic」を findTopicToStart 相当のロジックで算出する純関数。
// rows は section_index ASC, topic_index ASC の順で並んでいる前提。
func decideNextTopic(rows []db.GetCourseStructureWithProgressRow) *getEnrollmentNextTopicResponse {
	if len(rows) == 0 {
		return nil
	}

	latestIdx := -1
	for i, row := range rows {
		if !row.ProgressStatus.Valid || !row.ProgressUpdatedAt.Valid {
			continue
		}
		if latestIdx == -1 {
			latestIdx = i
			continue
		}
		// タイブレーク: 同 timestamp なら後ろの行 (rows の並びで後) を優先
		if !row.ProgressUpdatedAt.Time.Before(rows[latestIdx].ProgressUpdatedAt.Time) {
			latestIdx = i
		}
	}

	if latestIdx == -1 {
		return rowToNextTopic(rows[0])
	}

	switch rows[latestIdx].ProgressStatus.String {
	case progressStatusInProgress:
		return rowToNextTopic(rows[latestIdx])
	case progressStatusCompleted:
		if latestIdx+1 < len(rows) {
			return rowToNextTopic(rows[latestIdx+1])
		}
		// 最終トピック完了: 過去に未完了の穴があればそこへ、全 COMPLETED なら null
		for _, row := range rows {
			if !row.ProgressStatus.Valid || row.ProgressStatus.String != progressStatusCompleted {
				return rowToNextTopic(row)
			}
		}
		return nil
	default:
		return rowToNextTopic(rows[0])
	}
}

func rowToNextTopic(row db.GetCourseStructureWithProgressRow) *getEnrollmentNextTopicResponse {
	return &getEnrollmentNextTopicResponse{
		SectionId: row.SectionID.String(),
		TopicId:   row.TopicID.String(),
	}
}

