	t.Run("draftコースでも著者本人ならアクセスできる", func(t *testing.T) {
		h := NewGetEnrollmentHandler(&mockGetEnrollmentQuery{
			authority: draftAuthorityBy(t, validUserID),
			rows:      sectionsRow(t, []rawSection{}),
