		assert.Equal(t, validTopic01ID, body.NextTopic.TopicId)
	})

	t.Run("セクション末尾COMPLETEDなら次セクションの先頭トピック", func(t *testing.T) {
		secs := []rawSection{
			{
				SectionId: validSection0ID, Title: "S0", Index: 0,
